UPDATE sys_schedule_job
job_name = #{jobName}, trigger_type = #{triggerType}, cron_expr = #{cronExpr}, interval_ms = #{intervalMs}, enabled = #{enabled}, remark = #{remark},
WHERE job_code = #{jobCode}

